import{_ as t,o,c as s,ag as r}from"./chunks/framework._658-eYr.js";const h=JSON.parse('{"title":"5 Git Commands That Will Save Your Life","description":"","frontmatter":{"id":"script-draft-01","title":"5 Git Commands That Will Save Your Life","type":"short","status":"draft","tags":["git","programming","tips","shorts"],"created":"2025-06-18T10:00:00.000Z","updated":"2025-06-18T10:00:00.000Z","word_count":142},"headers":[],"relativePath":"seed/channels/demo-channel/scripts/drafts/script-draft-01.md","filePath":"seed/channels/demo-channel/scripts/drafts/script-draft-01.md"}'),a={name:"seed/channels/demo-channel/scripts/drafts/script-draft-01.md"};function n(i,e,d,c,p,m){return o(),s("div",null,[...e[0]||(e[0]=[r("<p><em>[leans into camera, dead serious]</em></p><p>—trust a developer who says &quot;it works on my machine.&quot;</p><p><strong>Five git commands.</strong> That&#39;s it. Five commands that separate the &quot;I just started coding&quot; crowd from the &quot;I&#39;ve seen things&quot; veterans.</p><p><em>[holds up one finger]</em></p><p><strong>Number one: <code>git stash</code></strong>. Your PM walks in with an &quot;urgent fix.&quot; You&#39;re mid-feature. Instead of panic-committing garbage, you stash it. Clean slate. Fix the bug. Pop your stash. Chef&#39;s kiss.</p><p><em>[two fingers]</em></p><p><strong><code>git bisect</code>.</strong> Something broke. You don&#39;t know when. Bisect does a binary search through your commits to find the exact one that ruined everything. Like a detective, but useful.</p><p><em>[three fingers, speeding up]</em></p><p><strong><code>git reflog</code>.</strong> You did a hard reset and lost everything? No you didn&#39;t. Reflog remembers what you forgot. It&#39;s your git safety net.</p><p><em>[four fingers]</em></p><p><strong><code>git cherry-pick</code>.</strong> Grab one specific commit from another branch. Just that one. No merge. No drama.</p><p><em>[five fingers, intense]</em></p><p><strong><code>git worktree</code>.</strong> Run two branches simultaneously in separate folders. Review a PR while your feature branch keeps cooking.</p><p><em>[beat]</em></p><p>Five commands. Zero excuses. And the next time someone says they &quot;lost their code&quot; — you should never—</p>",15)])])}const g=t(a,[["render",n]]);export{h as __pageData,g as default};
